        foreach ($products as $product) {
            // Extract reference from name (last part after ' - ')
            $parts = explode(' - ', $product[0]);
            $ref = end($parts);
            $cleanImageName = str_replace(['/', ' ', '?', '#', '&'], ['-', '-', '', '', ''], $ref) . '.jpg';

            $price = $product[2];
            $discountPercent = $product[3];
            $resellerPrice = $price - ($price * $discountPercent / 100);

            DB::table('products')->insert([
                'name'                => $product[0],
                'category'            => $product[1],
                'price'               => $price,
                'discount_percentage' => $discountPercent,
                'reseller_price'      => round($resellerPrice, 2),
                'stock'               => $product[4],
                'description'         => $product[5],
                'is_active'           => $product[6],
                'image'               => 'products/' . $cleanImageName,
                'created_at'          => now(),
                'updated_at'          => now(),
            ]);
        }
